import { Student, GlobalConfig, Priority, InvoiceDetail, Attendance } from '../types';

export const calculateAgeInMonths = (dob: string): number => {
  const birth = new Date(dob);
  const now = new Date();
  return (now.getFullYear() - birth.getFullYear()) * 12 + (now.getMonth() - birth.getMonth());
};

export const formatCurrency = (amount: number): string => {
  return new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(amount);
};

export const calculateInvoice = (
  student: Student,
  config: GlobalConfig,
  attendanceData: Attendance[],
  currentMonth: number,
  currentYear: number
): InvoiceDetail => {
  const ageMonths = calculateAgeInMonths(student.dob);

  // 1. Tuition
  let tuition = ageMonths > 36 ? config.tuitionOver36 : config.tuitionUnder36;
  if (student.priority === Priority.TeacherChild || student.priority === Priority.TeacherNiece) {
    tuition = 0;
  }

  // 2. Meal Fee
  // (Standard days * 32k) - (Absent days last month * 32k)
  const lastMonth = currentMonth === 1 ? 12 : currentMonth - 1;
  const lastYear = currentMonth === 1 ? currentYear - 1 : currentYear;
  const lastMonthAttendance = attendanceData.find(
    a => a.studentId === student.id && a.month === lastMonth && a.year === lastYear
  );
  const absentDays = lastMonthAttendance ? lastMonthAttendance.absentDays : 0;
  const mealFee = (config.standardDays * config.mealFeePerDay) - (absentDays * config.mealFeePerDay);

  // 3. Gifted Subjects
  let giftedTotal = 0;
  const giftedBreakdown: string[] = [];

  if (student.giftedSubjects.english) {
    giftedTotal += config.giftedFees.english;
    giftedBreakdown.push(`Anh văn: ${formatCurrency(config.giftedFees.english)}`);
  }
  if (student.giftedSubjects.drawing) {
    giftedTotal += config.giftedFees.drawing;
    giftedBreakdown.push(`Vẽ: ${formatCurrency(config.giftedFees.drawing)}`);
  }
  if (student.giftedSubjects.rhythm) {
    // Free rhythm for teacher's kin
    const isFree = student.priority === Priority.TeacherChild || student.priority === Priority.TeacherNiece;
    const fee = isFree ? 0 : config.giftedFees.rhythm;
    giftedTotal += fee;
    giftedBreakdown.push(`Nhịp điệu: ${formatCurrency(fee)} ${isFree ? '(Miễn phí)' : ''}`);
  }

  // 4. Annual Fees (for new students)
  const annualFees = student.isNewStudent ? (config.infrastructureFee + config.materialFee) : 0;

  const total = tuition + mealFee + giftedTotal + annualFees + config.extraFee;

  return {
    student,
    tuition,
    mealFee,
    giftedTotal,
    annualFees,
    extraFee: config.extraFee,
    total,
    calculationInfo: {
      ageInMonths: ageMonths,
      absentDaysLastMonth: absentDays,
      giftedBreakdown
    }
  };
};

export const generateZaloMessage = (invoice: InvoiceDetail, month: number, year: number): string => {
  const { student, total, tuition, mealFee, giftedTotal, annualFees, extraFee, calculationInfo } = invoice;
  return `🌸 MẦM NON MẦM XANH - PHIẾU THU T${month}/${year} 🌸

Kính gửi Phụ huynh bé ${student.name.toUpperCase()},
Nhà trường xin gửi thông báo học phí chi tiết:

- Học phí: ${formatCurrency(tuition)} (${calculationInfo.ageInMonths} tháng)
- Tiền ăn: ${formatCurrency(mealFee)} (${configDays(calculationInfo.absentDaysLastMonth)})
- Năng khiếu: ${formatCurrency(giftedTotal)}
${annualFees > 0 ? `- Phí nhập học (CSVC+HP): ${formatCurrency(annualFees)}\n` : ''}- Phụ phí: ${formatCurrency(extraFee)}

🔴 TỔNG TIỀN: ${formatCurrency(total)}

