/**
 * Lấy mốc tháng 9 là 12 tháng, tháng 8 là 1 tháng.
 * Công thức: Số_tháng = (8 - Tháng_Thu_Phí) % 12 + 1
 */
export const calculateMonthsRemaining = (month: number): number => {
  // JavaScript % operator returns negative for negative numbers, handle appropriately
  return ((8 - month) % 12 + 12) % 12 + 1;
};

export const calculateInvoice = (
  student: Student,
