  if (student.giftedSubjects.drawing) {
    giftedTotal += config.giftedFees.drawing;
    giftedBreakdown.push(`Vẽ: ${formatCurrency(config.giftedFees.drawing)}`);
  }
  if (student.giftedSubjects.rhythm) {
    const isFree = student.priority === Priority.TeacherChild || student.priority === Priority.TeacherNiece;
    const fee = isFree ? 0 : config.giftedFees.rhythm;
    giftedTotal += fee;
    giftedBreakdown.push(`Nhịp điệu: ${formatCurrency(fee)} ${isFree ? '(Miễn phí)' : ''}`);
  }

  // 4. CSVC and Material Fees for NEW students
  // Calculated based on remaining months in academic year
  let csvcFee = 0;
  let materialFee = 0;
  if (student.isNewStudent) {
    csvcFee = monthsRemaining * config.unitCSVC;
    const matUnitPrice = ageMonths >= 36 ? config.unitMaterialLon : config.unitMaterialNho;
    materialFee = monthsRemaining * matUnitPrice;
  }

  const total = tuition + mealFee + giftedTotal + csvcFee + materialFee + config.extraFee;

  return {
    student,
    tuition,
    mealFee,
    giftedTotal,
    csvcFee,
    materialFee,
    extraFee: config.extraFee,
    total,
    calculationInfo: {
      ageInMonths: ageMonths,
      absentDaysLastMonth: absentDays,
      monthsRemaining,
      giftedBreakdown
    }
  };
};

