export const calculateInvoice = (
  student: Student,
  config: GlobalConfig,
  attendanceData: Attendance[],
  currentMonth: number,
  currentYear: number
): InvoiceDetail => {
  const ageMonths = calculateAgeInMonths(student.dob);
  const monthsRemaining = calculateMonthsRemaining(currentMonth);

  // 1. Học phí
  let tuition = ageMonths >= 36 ? config.tuitionOver36 : config.tuitionUnder36;
  if (student.priority === Priority.TeacherChild || student.priority === Priority.TeacherNiece) {
    tuition = 0;
  }

  // 2. Tiền ăn gốc (Ngày chuẩn * đơn giá)
  const mealFeeBase = config.standardDays * config.mealFeePerDay;

  // 3. Tiền vắng tháng trước để trừ lại
