    student,
    tuition,
    mealFee: mealFeeFinal,
    giftedTotal,
    csvcFee,
    materialFee,
    extraFee: config.extraFee,
    total,
    calculationInfo: {
      ageInMonths: ageMonths,
      absentDaysLastMonth: absentDays,
      monthsRemaining,
      giftedBreakdown
    }
  };
};

