              <input 
                type="number"
                value={currentYear}
                onChange={(e) => setCurrentYear(parseInt(e.target.value) || 2026)}
                className="w-full bg-white border border-slate-200 rounded-lg text-sm font-bold p-2 outline-none focus:ring-2 focus:ring-emerald-500"
              />
            </div>
          </div>
          <div>
            <label className="text-[10px] text-slate-400 font-bold block mb-1">Số ngày học chuẩn</label>
            <input 
              type="number" 
              value={config.standardDays}
              onChange={(e) => setConfig({...config, standardDays: parseInt(e.target.value) || 0})}
              className="w-full bg-white border border-slate-200 rounded-lg text-sm font-bold p-2 outline-none focus:ring-2 focus:ring-emerald-500"
            />
          </div>
          <div className="pt-2 border-t border-slate-200">
             <div className="flex justify-between text-[10px]">
               <span className="text-slate-400 font-bold uppercase">Số tháng niên học:</span>
               <span className="text-emerald-600 font-black">{calculateMonthsRemaining(currentMonth)} tháng</span>
             </div>
          </div>
        </div>

        <nav className="flex-1 space-y-1">
          <SidebarItem icon={LayoutDashboard} label="Tổng quan" active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} />
          <SidebarItem icon={CalendarCheck} label="Điểm danh" active={activeTab === 'attendance'} onClick={() => setActiveTab('attendance')} />
          <SidebarItem icon={FileText} label="Phiếu thu" active={activeTab === 'invoices'} onClick={() => setActiveTab('invoices')} />
          <SidebarItem icon={Users} label="Học sinh" active={activeTab === 'students'} onClick={() => setActiveTab('students')} />
          <SidebarItem icon={Settings} label="Cấu hình phí" active={activeTab === 'settings'} onClick={() => setActiveTab('settings')} />
        </nav>
      </div>

      {/* Main Content */}
      <div className="flex-1 overflow-y-auto">
        <header className="h-16 bg-white border-b border-slate-100 flex items-center justify-between px-8 sticky top-0 z-10 no-print">
          <h2 className="text-lg font-semibold text-slate-800">
             T{currentMonth}/{currentYear} - {activeTab === 'dashboard' ? 'Tổng quan' : activeTab === 'settings' ? 'Cấu hình' : 'MXMS'}
          </h2>
          <div className="flex items-center space-x-4">
            <div className="flex items-center space-x-2 pl-4 border-l border-slate-100">
              <div className="w-8 h-8 rounded-full bg-emerald-500 text-white flex items-center justify-center font-bold text-xs shadow-sm">AD</div>
              <span className="text-sm font-bold text-slate-700">Trần Thị Trúc Giang</span>
            </div>
          </div>
        </header>

        <main className="p-8">
          {activeTab === 'dashboard' && (
            <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <Card className="flex items-center justify-between border-l-4 border-l-emerald-500">
                  <div>
                    <p className="text-xs text-slate-500 font-bold uppercase tracking-wider">Doanh thu T{currentMonth}</p>
                    <h3 className="text-2xl font-bold text-slate-800 mt-1">{formatCurrency(dashboardStats.totalRevenue)}</h3>
                  </div>
                  <TrendingUp className="text-emerald-500" size={32} />
                </Card>
                <Card className="flex items-center justify-between border-l-4 border-l-blue-500">
                  <div>
                    <p className="text-xs text-slate-500 font-bold uppercase tracking-wider">Sĩ số</p>
                    <h3 className="text-2xl font-bold text-slate-800 mt-1">{dashboardStats.studentCount} trẻ</h3>
                  </div>
                  <Users className="text-blue-500" size={32} />
                </Card>
                <Card className="flex items-center justify-between border-l-4 border-l-orange-500">
                  <div>
                    <p className="text-xs text-slate-500 font-bold uppercase tracking-wider">Tiền ăn/ngày</p>
                    <h3 className="text-2xl font-bold text-slate-800 mt-1">{formatCurrency(config.mealFeePerDay)}</h3>
                  </div>
                  <Calendar className="text-orange-500" size={32} />
                </Card>
              </div>
            </div>
          )}

          {activeTab === 'attendance' && (
            <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
              <Card>
                <div className="overflow-x-auto">
                  <table className="w-full text-left border-collapse">
                    <thead>
                      <tr className="border-b border-slate-100 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                        <th className="pb-4 pl-2">Tên bé</th>
                        <th className="pb-4">Loại hình</th>
                        <th className="pb-4 text-center">Vắng (T{currentMonth === 1 ? 12 : currentMonth - 1})</th>
                        <th className="pb-4 text-right pr-2">Phiếu thu</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-50">
                      {students.map((student) => {
                        const lastMonth = currentMonth === 1 ? 12 : currentMonth - 1;
                        const lastYear = currentMonth === 1 ? currentYear - 1 : currentYear;
                        const att = attendance.find(a => a.studentId === student.id && a.month === lastMonth && a.year === lastYear);
                        return (
                          <tr key={student.id} className="group hover:bg-slate-50/50">
                            <td className="py-4 pl-2 font-bold text-slate-800">{student.name}</td>
                            <td className="py-4">
                               <button 
                                 onClick={() => toggleNewStudent(student.id)}
                                 className={`text-[10px] px-2 py-1 rounded-lg font-black uppercase transition-all ${
                                   student.isNewStudent ? 'bg-orange-500 text-white' : 'bg-slate-100 text-slate-400'
                                 }`}
                               >
                                 {student.isNewStudent ? 'Bé Mới' : 'Bé Cũ'}
                               </button>
                            </td>
                            <td className="py-4">
                              <div className="flex items-center justify-center space-x-4">
                                <button 
                                  onClick={() => handleAttendanceChange(student.id, -1)}
                                  className="w-8 h-8 rounded-full border border-slate-200 flex items-center justify-center text-slate-500 hover:bg-emerald-500 hover:text-white transition-all font-bold"
                                >-</button>
                                <span className="font-black text-slate-700 w-4 text-center">{att?.absentDays || 0}</span>
                                <button 
                                  onClick={() => handleAttendanceChange(student.id, 1)}
                                  className="w-8 h-8 rounded-full border border-slate-200 flex items-center justify-center text-slate-500 hover:bg-emerald-500 hover:text-white transition-all font-bold"
                                >+</button>
                              </div>
                            </td>
                            <td className="py-4 text-right pr-2">
                              <button 
                                onClick={() => { setSelectedStudent(student); setActiveTab('invoices'); }}
                                className="px-3 py-1 bg-emerald-50 text-emerald-600 rounded-lg text-[10px] font-black uppercase"
                              >Xem phí</button>
                            </td>
                          </tr>
                        );
                      })}
                    </tbody>
                  </table>
                </div>
              </Card>
            </div>
          )}

          {activeTab === 'invoices' && (
            <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
              {!selectedStudent ? (
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                  {students.map(student => (
                    <Card key={student.id} onClick={() => setSelectedStudent(student)} className="cursor-pointer hover:border-emerald-500 transition-all flex justify-between items-center group">
                      <span className="font-bold text-slate-800 group-hover:text-emerald-600">{student.name}</span>
                      <ChevronRight className="text-slate-300" size={16} />
                    </Card>
                  ))}
                </div>
              ) : (
                <div className="flex flex-col lg:flex-row gap-8 items-start">
                  {/* Traditional Styled Invoice */}
                  <div className="bg-white p-12 shadow-xl border border-slate-200 w-full max-w-[800px] text-slate-900 font-serif leading-relaxed" id="invoice-print">
                    <div className="text-center mb-8">
                      <h2 className="text-2xl font-bold uppercase tracking-wide">GIẤY BÁO ĐÓNG TIỀN HỌC PHÍ THÁNG {currentMonth} NĂM {currentYear}</h2>
                    </div>

                    {(() => {
                      const inv = calculateInvoice(selectedStudent, config, attendance, currentMonth, currentYear);
                      return (
                        <div className="space-y-4 text-lg">
                          <p>- Họ và tên trẻ : <span className="font-bold uppercase">{selectedStudent.name}</span> SN {new Date(selectedStudent.dob).toLocaleDateString('vi-VN')} - {inv.calculationInfo.ageInMonths} tháng.</p>

                          <div className="grid grid-cols-[1fr_auto_auto] gap-x-4 items-center">
                            <span>- Tiền học phí trong tháng :</span>
                            <span className="w-12 text-center">:</span>
                            <span className="font-bold">{formatCurrency(inv.tuition)} đồng.</span>

                            <span>- Tiền ăn trong tháng ({config.standardDays} ngày x {formatCurrency(config.mealFeePerDay)}) :</span>
                            <span className="w-12 text-center">:</span>
                            <span className="font-bold">{formatCurrency(config.standardDays * config.mealFeePerDay)} đồng.</span>

                            {inv.calculationInfo.giftedBreakdown.map((item, idx) => (
                              <React.Fragment key={idx}>
                                <span>- Học {item} :</span>
                                <span className="w-12 text-center">:</span>
                                <span className="font-bold">{item.split(' ').pop()} đồng.</span>
                              </React.Fragment>
                            ))}

                            <span>- Các khoản phụ thu (Vệ sinh phí, Gaz, Điện, Nước bình...) :</span>
                            <span className="w-12 text-center">:</span>
                            <span className="font-bold">{formatCurrency(config.extraFee)} đồng.</span>

                            {inv.csvcFee > 0 && (
                              <>
                                <span>- Phí CSVC ({inv.calculationInfo.monthsRemaining} tháng x {formatCurrency(config.unitCSVC)}) :</span>
                                <span className="w-12 text-center">:</span>
                                <span className="font-bold">{formatCurrency(inv.csvcFee)} đồng.</span>
                              </>
                            )}

                            {inv.materialFee > 0 && (
                              <>
                                <span>- Học phẩm ({inv.calculationInfo.monthsRemaining} tháng) :</span>
                                <span className="w-12 text-center">:</span>
                                <span className="font-bold">{formatCurrency(inv.materialFee)} đồng.</span>
                              </>
                            )}

                            <span>- Số ngày nghỉ có phép trong tháng : {inv.calculationInfo.absentDaysLastMonth} ngày. Trừ lại :</span>
                            <span className="w-12 text-center">:</span>
                            <span className="font-bold">{formatCurrency(inv.calculationInfo.absentDaysLastMonth * config.mealFeePerDay)} đồng.</span>
                          </div>

                          <div className="text-center py-6">
                            <h3 className="text-2xl font-bold uppercase inline-block border-b-2 border-slate-900 pb-1">TỔNG CỘNG : &nbsp;&nbsp;{formatCurrency(inv.total)} đồng.</h3>
                          </div>

                          <div className="space-y-2 text-base italic">
                            <p>Thông tin chuyển khoản: Tên thụ hưởng: <span className="font-bold uppercase">Trần Thị Trúc Giang</span></p>
                            <p>Số tài khoản: <span className="font-bold">6350205 014046</span> Tại Ngân hàng Agribank Phước Kiển</p>
                            <p className="font-bold">Nội dung chuyển khoản: tên trẻ, tên lớp.</p>
                            <p className="font-bold mt-4">Phụ huynh vui lòng đóng học phí từ ngày 1 đến 10 tây hàng tháng. <span className="font-normal">Rất mong phụ huynh đóng học phí đúng thời gian qui định của nhà trường.</span></p>
                          </div>

                          <div className="flex justify-between items-start mt-12 pt-8">
                             <div className="w-1/3 border-t border-slate-200"></div>
                             <div className="text-center w-1/3">
                               <p className="font-bold text-xl">Xin chân thành cảm ơn!</p>
                             </div>
                          </div>
                        </div>
                      );
                    })()}
                  </div>

                  <div className="space-y-6 w-full lg:w-80 no-print">
                    <button onClick={handlePrint} className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black text-sm uppercase flex items-center justify-center space-x-2 shadow-lg shadow-slate-200">
                      <Printer size={20} />
                      <span>Lưu & In phiếu</span>
                    </button>
                    <button className="w-full py-4 bg-blue-600 text-white rounded-2xl font-black text-sm uppercase flex items-center justify-center space-x-2 shadow-lg shadow-blue-200">
                      <Share2 size={20} />
                      <span>Gửi Zalo</span>
                    </button>
                    <button onClick={() => setSelectedStudent(null)} className="w-full py-3 bg-slate-100 text-slate-500 rounded-xl font-bold text-sm">Quay lại danh sách</button>
                  </div>
                </div>
              )}
            </div>
          )}

          {activeTab === 'settings' && (
            <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 max-w-4xl">
              <div className="grid grid-cols-1 gap-8">
                <Card>
                  <h5 className="font-bold text-slate-800 mb-6 flex items-center uppercase text-sm tracking-widest">
                    <CalendarCheck className="mr-3 text-emerald-500" size={24} />
                    Học phí & Tiền ăn
                  </h5>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div className="space-y-2">
                      <label className="text-xs font-bold text-slate-400 uppercase">Lớp Nhỏ (Dưới 36th)</label>
                      <input type="number" value={config.tuitionUnder36} onChange={(e) => setConfig({...config, tuitionUnder36: parseInt(e.target.value) || 0})} className="w-full bg-slate-50 border border-slate-200 rounded-xl py-3 px-4 font-bold" />
                    </div>
                    <div className="space-y-2">
                      <label className="text-xs font-bold text-slate-400 uppercase">Lớp Lớn (Trên 36th)</label>
                      <input type="number" value={config.tuitionOver36} onChange={(e) => setConfig({...config, tuitionOver36: parseInt(e.target.value) || 0})} className="w-full bg-slate-50 border border-slate-200 rounded-xl py-3 px-4 font-bold" />
                    </div>
                    <div className="space-y-2">
                      <label className="text-xs font-bold text-slate-400 uppercase">Tiền ăn/ngày (VNĐ)</label>
                      <input type="number" value={config.mealFeePerDay} onChange={(e) => setConfig({...config, mealFeePerDay: parseInt(e.target.value) || 0})} className="w-full bg-slate-50 border border-slate-200 rounded-xl py-3 px-4 font-bold" />
                    </div>
                    <div className="space-y-2">
                      <label className="text-xs font-bold text-slate-400 uppercase">Phụ phí tháng (VNĐ)</label>
                      <input type="number" value={config.extraFee} onChange={(e) => setConfig({...config, extraFee: parseInt(e.target.value) || 0})} className="w-full bg-slate-50 border border-slate-200 rounded-xl py-3 px-4 font-bold" />
                    </div>
                  </div>
                </Card>

                <Card>
                  <h5 className="font-bold text-slate-800 mb-6 flex items-center uppercase text-sm tracking-widest">
                    <Settings className="mr-3 text-orange-500" size={24} />
                    Phí Tự Động (Bé Mới)
                  </h5>
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                    <div className="space-y-2">
                      <label className="text-xs font-bold text-slate-400 uppercase">CSVC (Hàng tháng)</label>
                      <input type="number" value={config.unitCSVC} onChange={(e) => setConfig({...config, unitCSVC: parseInt(e.target.value) || 0})} className="w-full bg-slate-50 border border-slate-200 rounded-xl py-3 px-4 font-bold" />
                    </div>
                    <div className="space-y-2">
                      <label className="text-xs font-bold text-slate-400 uppercase">Học phẩm Lớp Lớn</label>
                      <input type="number" value={config.unitMaterialLon} onChange={(e) => setConfig({...config, unitMaterialLon: parseInt(e.target.value) || 0})} className="w-full bg-slate-50 border border-slate-200 rounded-xl py-3 px-4 font-bold" />
                    </div>
                    <div className="space-y-2">
                      <label className="text-xs font-bold text-slate-400 uppercase">Học phẩm Lớp Nhỏ</label>
                      <input type="number" value={config.unitMaterialNho} onChange={(e) => setConfig({...config, unitMaterialNho: parseInt(e.target.value) || 0})} className="w-full bg-slate-50 border border-slate-200 rounded-xl py-3 px-4 font-bold" />
                    </div>
                  </div>
                </Card>

                <div className="flex justify-end">
                  <button className="px-12 py-4 bg-emerald-500 text-white rounded-2xl font-black uppercase shadow-xl shadow-emerald-200 hover:bg-emerald-600">Lưu cấu hình</button>
                </div>
              </div>
            </div>
          )}
        </main>
      </div>
    </div>
  );
}
